('9 Days Tanzania Safari + Zanzibar Beach', '9-days-safari-zanzibar', 'Safari & Beach', 'Complete Tanzania experience combining wildlife safari with beach relaxation', 'The ultimate Tanzania adventure combining the best wildlife destinations with pristine Zanzibar beaches. Perfect for honeymooners and those seeking variety.', '["Honeymooners", "Beach lovers", "Complete experience"]'::jsonb, '9 days / 8 nights', 'Arusha → Zanzibar', '["Serengeti wildlife", "Ngorongoro Crater", "Zanzibar Stone Town", "Beach relaxation"]'::jsonb, '[{"day": 1, "title": "Arusha → Tarangire", "description": "Game drive", "overnight": "Tarangire"}, {"day": 2, "title": "Tarangire → Serengeti", "description": "Afternoon game drive", "overnight": "Serengeti"}, {"day": 3, "title": "Serengeti full day", "description": "Full day game drive", "overnight": "Serengeti"}, {"day": 4, "title": "Serengeti → Ngorongoro", "description": "Morning game drive, transfer", "overnight": "Karatu"}, {"day": 5, "title": "Ngorongoro Crater", "description": "Crater tour", "overnight": "Arusha"}, {"day": 6, "title": "Fly to Zanzibar", "description": "Beach time", "overnight": "Zanzibar"}, {"day": 7, "title": "Zanzibar", "description": "Beach day", "overnight": "Zanzibar"}, {"day": 8, "title": "Stone Town Tour", "description": "Cultural tour", "overnight": "Zanzibar"}, {"day": 9, "title": "Departure", "description": "Fly home", "overnight": ""}]'::jsonb, '["All park fees", "Internal flights", "Accommodation", "Meals on safari"]'::jsonb, '["International flights", "Visa", "Travel insurance"]'::jsonb, '/images/destinations/zanzibar-beach.jpg', 4200, 9.6, 124, 'Moderate', true, true, 2);
